def evaluate_prompt_advanced(prompt_version):
    test_cases = [
        {
            "input": "What's my balance?",
            "tests": {
                "format": lambda r: "Account ID" in r,  # Should ask for ID
                "accuracy": lambda r: "$" not in r,  # Should not show balance yet
                "tone": lambda r: r.lower().startswith("to check")  # Professional
            }
        }
    ]

    results = {
        "format": [],
        "accuracy": [],
        "tone": []
    }

    for case in test_cases:
        response = call_llm(prompt_version, case["input"])
        for criterion, test_fn in case["tests"].items():
            if test_fn(response):
                results[criterion].append(True)
            else:
                results[criterion].append(False)

    # Calculate scores
    scores = {
        criterion: (sum(passes) / len(passes)) * 100
        for criterion, passes in results.items()
    }

    overall = sum(scores.values()) / len(scores)
    print(f"Overall: {overall}%")
    print(f"Format: {scores['format']}%")
    print(f"Accuracy: {scores['accuracy']}%")
    print(f"Tone: {scores['tone']}%")

    return overall

